  1	import * as _ from 'lodash-es';
  2	import { Tooltip, SelectOption } from '@patternfly/react-core';
  3	import {
  4	  DEFAULT_ALL_VALUE,
  5	  ListVariableDefinition,
  6	  VariableDefinition,
  7	  VariableName,
  8	} from '@perses-dev/core';
  9	
 10	import * as React from 'react';
 11	import { useTranslation } from 'react-i18next';
 12	
 13	import { SingleTypeaheadDropdown } from '../../console/utils/single-typeahead-dropdown';
 14	
 15	import {
 16	  useListVariableState,
 17	  useVariableDefinitionActions,
 18	  useVariableDefinitionAndState,
 19	  useVariableDefinitions,
 20	} from '@perses-dev/dashboards';
 21	import { useListVariablePluginValues, VariableOption } from '@perses-dev/plugin-system';
 22	
 23	/**
 24	 * This file is approximately the equal of `perses/ui/dashboards/src/components/Variables/Variable`
 25	 * When we get to adding customizable actions to the dashboards we should reconsider what we
 26	 * want to keep and what we want to reuse from perses
 27	 */
 28	
 29	const intervalVariableRegExps = ['__interval', '__rate_interval', '__auto_interval_[a-z]+'];
 30	
 31	const isIntervalVariable = (itemKey: string): boolean =>
 32	  _.some(intervalVariableRegExps, (re) => itemKey?.match(new RegExp(`\\$${re}`, 'g')));
 33	
 34	const VariableOptionComponent = ({ value, isSelected, ...rest }) =>
 35	  isIntervalVariable(String(value)) ? (
 36	    <Tooltip content={value}>
 37	      <SelectOption value={value} isSelected={isSelected || false}>
 38	        Auto interval
 39	      </SelectOption>
 40	    </Tooltip>
 41	  ) : (
 42	    <SelectOption value={value} isSelected={isSelected || false} {...rest}>
 43	      {value === DEFAULT_ALL_VALUE ? 'All' : value}
 44	    </SelectOption>
 45	  );
 46	
 47	function ListVariable({ name, id }: VariableDropdownProps) {
 48	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 49	
 50	  const ctx = useVariableDefinitionAndState(name);
 51	  const definition = ctx.definition as ListVariableDefinition;
 52	  const variablesOptionsQuery = useListVariablePluginValues(definition);
 53	  const { setVariableValue, setVariableLoading, setVariableOptions } =
 54	    useVariableDefinitionActions();
 55	  const { selectedOptions, value, loading, options, viewOptions } = useListVariableState(
 56	    definition?.spec,
 57	    ctx.state,
 58	    variablesOptionsQuery,
 59	  );
 60	
 61	  const allowAllValue = definition?.spec.allowAllValue === true;
 62	
 63	  // Update value when changed
 64	  React.useEffect(() => {
 65	    if (value) {
 66	      setVariableValue(name, value);
 67	    }
 68	  }, [setVariableValue, name, value]);
 69	
 70	  // Update loading when changed
 71	  React.useEffect(() => {
 72	    setVariableLoading(name, loading);
 73	  }, [setVariableLoading, name, loading]);
 74	
 75	  // Update options when changed
 76	  React.useEffect(() => {
 77	    if (options) {
 78	      setVariableOptions(name, options);
 79	    }
 80	  }, [setVariableOptions, name, options]);
 81	
 82	  const onChangeFunction = React.useCallback(
 83	    (value: string): void => {
 84	      if ((value === null || (Array.isArray(value) && value.length === 0)) && allowAllValue) {
 85	        setVariableValue(name, DEFAULT_ALL_VALUE);
 86	      } else {
 87	        setVariableValue(name, value);
 88	      }
 89	    },
 90	    [setVariableValue, allowAllValue, name],
 91	  );
 92	
 93	  if (_.isEmpty(viewOptions)) {
 94	    return null;
 95	  }
 96	
 97	  const singleSelectedItem = Array.isArray(selectedOptions)
 98	    ? selectedOptions.at(0)
 99	    : selectedOptions;
100	
101	  const items: {
102	    value: string;
103	    children: string;
104	  }[] = _.map<VariableOption>(viewOptions, (option: VariableOption) => ({
105	    value: option.label,
106	    children: option.label,
107	  }));
108	
109	  const title = definition?.spec.display?.name ?? name;
110	
111	  return (
112	    <div
113	      className="form-group monitoring-dashboards__dropdown-wrap"
114	      data-test={`${name.toLowerCase()}-dropdown`}
115	    >
116	      <label htmlFor={`${id}-dropdown`} className="monitoring-dashboards__dropdown-title">
117	        {title}
118	      </label>
119	      <SingleTypeaheadDropdown
120	        items={items}
121	        onChange={onChangeFunction}
122	        OptionComponent={VariableOptionComponent}
123	        selectedKey={singleSelectedItem.label}
124	        hideClearButton
125	        resizeToFit
126	        placeholder={t('Select a dashboard from the dropdown')}
127	      />
128	    </div>
129	  );
130	}
131	
132	export const AllVariableDropdowns: React.FC = () => {
133	  const variableDefinitions: VariableDefinition[] = useVariableDefinitions();
134	
135	  if (!variableDefinitions) {
136	    return null;
137	  }
138	
139	  return (
140	    <>
141	      {variableDefinitions.map((v) => (
142	        <VariableComponent key={v.spec.name} name={v.spec.name} />
143	      ))}
144	    </>
145	  );
146	};
147	
148	export function VariableComponent({ name }: VariableProps) {
149	  const ctx = useVariableDefinitionAndState(name);
150	  const kind = ctx.definition?.kind;
151	  switch (kind) {
152	    // Openshift doesn't support this, so ignore for now
153	    // case 'TextVariable':
154	    // return <TextVariable name={name} source={source} />;
155	    case 'ListVariable':
156	      return <ListVariable id={name} name={name} />;
157	  }
158	
159	  return <div>Unsupported Variable Kind: ${kind}</div>;
160	}
161	
162	type VariableProps = {
163	  name: VariableName;
164	};
165	
166	type VariableDropdownProps = {
167	  id: string;
168	  name: string;
169	};

